function.body:
v_ResultStr VARCHAR2(2000):='';
  v_Message VARCHAR2(2000):='';
  v_Result NUMBER:=1; -- 0=failure
  v_Record_ID VARCHAR2(32);
  v_AD_User_ID VARCHAR2(32);
  v_AD_org_ID VARCHAR2(32);
  v_AD_Client_ID  VARCHAR2(32);
  v_fin_paymentmethod_id C_BPARTNER.FIN_PAYMENTMETHOD_ID%TYPE;
  v_quotation_task NUMBER;
  v_update_row VARCHAR2(1);
  v_sproctm_task_workforce_id  VARCHAR2(32);
  v_C_Order_ID VARCHAR2(32);
  v_C_OrderLine_ID VARCHAR2(32);
  v_C_DOCTYPE_ID VARCHAR2(32);
  v_DocumentNo NVARCHAR2(30) ;
  v_include VARCHAR2(5);
  v_totalDetails NUMBER;
  v_sproctm_task_cif_id VARCHAR2(32);
  v_sproctm_task_machine_id VARCHAR2(32);
  TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;

  BEGIN
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID) ;
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL) ;
  BEGIN --BODY
    -- Get PARAMETERS
    v_ResultStr:='ReadingParameters';
    FOR Cur_Parameter IN
      (SELECT i.Record_ID,i.AD_org_ID, i.AD_User_ID, i.AD_Client_ID, i.AD_Org_ID, p.ParameterName,
        p.P_String, p.P_Number, p.P_Date, p.P_Date_To, p.p_string as update_row
      FROM AD_PINSTANCE i
      LEFT JOIN AD_PINSTANCE_PARA p ON i.AD_PInstance_ID=p.AD_PInstance_ID
      WHERE i.AD_PInstance_ID=p_PInstance_ID
      ORDER BY p.SeqNo
      ) 
    LOOP
      v_Record_ID:=Cur_Parameter.Record_ID;
      v_AD_User_ID:=Cur_Parameter.AD_User_ID;
	  v_AD_org_ID:=Cur_Parameter.AD_org_ID;
	  v_AD_Client_ID:=Cur_Parameter.AD_Client_ID;
      v_update_row:=Cur_Parameter.update_row;
    END LOOP; -- Get Parameter
    DBMS_OUTPUT.PUT_LINE('  Record_ID=' || v_Record_ID) ;
    DECLARE
      v_ma_costCenter_id VARCHAR2(32);
	  v_MA_CostCenter_Version_ID VARCHAR2(32);
      v_scc_datefrom VARCHAR2(32);
		v_sql VARCHAR2(2000);
    TYPE RECORD IS REF CURSOR;
      Cur_Task RECORD;
      Cur_Operarios RECORD;
      Cur_CIF RECORD;
      Cur_Machine RECORD;
    BEGIN
      v_ResultStr:='StartLoop';
        -- Determnar la version del centro de costos a tomar la data
		select em_sproctm_MA_CostCenter_id into v_ma_costCenter_id from C_ProjectPhase 
		WHERE C_ProjectPhase_id = v_Record_ID ;
		IF( v_ma_costCenter_id is null) THEN
	          RAISE_APPLICATION_ERROR(-20000,'No se ha encontrado el Centro de Costo en la Fase.');
	  	END IF;
		-- Determinar la Version del Centro de Costo a tomar la data
		SELECT MA_CostCenter_Version_ID into v_MA_CostCenter_Version_ID FROM MA_CostCenter_Version 
		WHERE validfrom = (
			Select  MAX(validfrom) FROM MA_CostCenter_Version where 
			MA_CostCenter_id = v_ma_costCenter_id
			) AND MA_CostCenter_id = v_ma_costCenter_id;


		-- Determinar todas las tareas de esa fase
	      FOR Cur_Task IN
			  (SELECT cpt.C_ProjectTask_ID , cpt.name as tarea
			   FROM C_ProjectTask cpt
			   LEFT JOIN C_ProjectPhase cpp ON cpp.C_ProjectPhase_ID = cpt.C_ProjectPhase_ID
			   where cpp.C_ProjectPhase_ID = v_Record_ID
			  ) 
			LOOP
                    -- Determinar el valor del costo unitario estandar
        		select max(scc.datefrom) into v_scc_datefrom
		        from MA_Costcenter_Employee mce
		        INNER JOIN 	C_Salary_Category sct on sct.C_Salary_Category_ID = mce.c_salary_category_id
                INNER JOIN 	C_Salary_Category_Cost scc on scc.C_Salary_Category_ID  = sct.C_Salary_Category_ID
                WHERE mce.MA_CostCenter_Version_ID = v_MA_CostCenter_Version_ID;

                -- Por cada tarea agregar cada registro de las solapas del Centro de Costo
                 -- Mano de Obra
                FOR Cur_Operarios IN 

                    select mce.MA_Costcenter_Employee_ID , mce.c_salary_category_id , mce.Quantity , 
                    mce.Costuom ,  scc.Cost
                    from MA_Costcenter_Employee mce
					INNER JOIN 	C_Salary_Category sct on sct.C_Salary_Category_ID = mce.c_salary_category_id
					INNER JOIN 	C_Salary_Category_Cost scc on scc.C_Salary_Category_ID  = sct.C_Salary_Category_ID
                    WHERE mce.MA_CostCenter_Version_ID = v_MA_CostCenter_Version_ID
					AND scc.datefrom >= v_scc_datefrom::date

                LOOP
                    --  Eliminar los registros ya agregados si no tienen detalle si ya existe detalle msg de error
                    -- Determinar si ya existe el registro no tomarlo en cuenta para el insert
                    SELECT COALESCE(sproctm_task_workforce_id , '')
                    INTO v_sproctm_task_workforce_id
                    FROM sproctm_task_workforce 
                    WHERE C_ProjectTask_ID = Cur_Task.C_ProjectTask_ID
                    AND c_salary_category_id = Cur_Operarios.c_salary_category_id;

                    v_include = 'Y';
                    IF(v_sproctm_task_workforce_id != '') THEN
                        -- Verifique si tiene detalles, si existen detalle sno elimnar ni sobreescribir.
                        SELECT count(*) as totalDetails
                        INTO v_totalDetails FROM sproctm_detail_cost 
                        WHERE record_id = v_sproctm_task_workforce_id;

                        IF( v_totalDetails = 0) THEN
                            DELETE FROM sproctm_task_workforce WHERE sproctm_task_workforce_id = v_sproctm_task_workforce_id;
                        ELSE
                            v_include = 'N';
                        END IF;

                    END IF;

                    IF(v_include = 'Y') THEN
                        INSERT INTO public.sproctm_task_workforce(
                        sproctm_task_workforce_id, ad_client_id, ad_org_id,
                        isactive, created, createdby, updated, updatedby, 
                        c_projecttask_id, c_salary_category_id,
                        qty_budget, costuom, cost_unit_standar,
                        total_cost_budget, qty_executed, total_cost)
                        VALUES (get_uuid(), v_AD_Client_ID, v_AD_org_ID,
                        'Y', now(), v_AD_User_ID, now(), v_AD_User_ID,
                        Cur_Task.C_ProjectTask_ID, Cur_Operarios.c_salary_category_id ,
                        Cur_Operarios.Quantity, Cur_Operarios.Costuom,  Cur_Operarios.Cost, 
                        (Cur_Operarios.Quantity * Cur_Operarios.Cost), 0, 0);
                    END IF;
                END LOOP;

                -- CIF
                FOR Cur_CIF IN 
            		select ic.MA_Indirect_Cost_id , icv.Cost_Uom, icv.Cost  from MA_Costcenter_IC ccic
                    INNER JOIN MA_CostCenter_Version mcv on ccic.MA_CostCenter_Version_ID = mcv.MA_CostCenter_Version_ID
                    INNER JOIN MA_Indirect_Cost ic on ic.MA_Indirect_Cost_ID = ccic.MA_Indirect_Cost_ID
                    INNER JOIN MA_Indirect_Cost_Value icv on icv.MA_Indirect_Cost_ID = ic.MA_Indirect_Cost_ID
                    WHERE mcv.MA_CostCenter_ID =  ( select em_sproctm_MA_CostCenter_id from C_ProjectPhase 
					                                WHERE C_ProjectPhase_id = v_Record_ID  )

                LOOP

                    --  Eliminar los registros ya agregados si no tienen detalle si ya existe detalle msg de error
                    -- Determinar si ya existe el registro no tomarlo en cuenta para el insert
                    SELECT COALESCE(sproctm_task_cif_id , '')
                    INTO v_sproctm_task_cif_id
                    FROM sproctm_task_cif 
                    WHERE C_ProjectTask_ID = Cur_Task.C_ProjectTask_ID
                    AND ma_indirect_cost_id = Cur_CIF.MA_Indirect_Cost_id;

                    v_include = 'Y';
                    IF(v_sproctm_task_cif_id != '') THEN
                        -- Verifique si tiene detalles, si existen detalle sno elimnar ni sobreescribir.
                        SELECT count(*) as totalDetails
                        INTO v_totalDetails FROM sproctm_detail_cost 
                        WHERE record_id = v_sproctm_task_cif_id;

                        IF( v_totalDetails = 0) THEN
                            DELETE FROM sproctm_task_cif WHERE sproctm_task_cif_id = v_sproctm_task_cif_id;
                        ELSE
                            v_include = 'N';
                        END IF;

                    END IF;

                    IF(v_include = 'Y') THEN

                        INSERT INTO sproctm_task_cif(
                                sproctm_task_cif_id, ad_client_id, ad_org_id, isactive, created, createdby,
                                updated, updatedby, c_projecttask_id, 
                                ma_indirect_cost_id, costuom, qty_budget, 
                                cost_unit_standar, total_cost_budget, 
                                uomcost_executed, unit_cost_executed, total_cost_executed)
                        VALUES (get_uuid(), v_AD_Client_ID, v_AD_org_ID, 'Y', now(), v_AD_User_ID,
                                now(), v_AD_User_ID, Cur_Task.C_ProjectTask_ID , 
                                Cur_CIF.MA_Indirect_Cost_id, Cur_CIF.Cost_Uom, 1,
                                Cur_CIF.Cost, (1 * Cur_CIF.Cost), 
                                0, 0, 0);
                    END IF;
                END LOOP;

                -- MAQUINARIA
                FOR Cur_Machine IN 

                    select mm.MA_Machine_id , mmc.Costuom , ccmch.Use , mmc.Costuomyear , mmc.Cost
                    from MA_CostCenter_Machine ccmch 	
                    INNER JOIN MA_CostCenter_Version mcv on mcv.MA_CostCenter_Version_ID = ccmch.MA_CostCenter_Version_ID
                    INNER JOIN MA_Machine mm on mm.MA_Machine_ID = ccmch.MA_Machine_ID
                    INNER JOIN MA_Machine_Cost mmc on mmc.MA_Machine_ID = mm.MA_Machine_ID
                    WHERE mcv.MA_CostCenter_ID =  ( select em_sproctm_MA_CostCenter_id from C_ProjectPhase 
					                                WHERE C_ProjectPhase_id = v_Record_ID  )

                LOOP 

                    --  Eliminar los registros ya agregados si no tienen detalle si ya existe detalle msg de error
                    -- Determinar si ya existe el registro no tomarlo en cuenta para el insert
                    SELECT COALESCE(sproctm_task_machine_id , '')
                    INTO v_sproctm_task_machine_id
                    FROM sproctm_task_machine 
                    WHERE C_ProjectTask_ID = Cur_Task.C_ProjectTask_ID
                    AND MA_Machine_id = Cur_Machine.MA_Machine_id;

                    v_include = 'Y';
                    IF(v_sproctm_task_machine_id != '') THEN
                        -- Verifique si tiene detalles, si existen detalle sno elimnar ni sobreescribir.
                        SELECT count(*) as totalDetails
                        INTO v_totalDetails FROM sproctm_detail_cost 
                        WHERE record_id = v_sproctm_task_machine_id;

                        IF( v_totalDetails = 0) THEN
                            DELETE FROM sproctm_task_machine WHERE sproctm_task_machine_id = v_sproctm_task_machine_id;
                        ELSE
                            v_include = 'N';
                        END IF;

                    END IF;

                    IF(v_include = 'Y') THEN

                        INSERT INTO sproctm_task_machine(
                        sproctm_task_machine_id, ad_client_id, ad_org_id, isactive, created, createdby,
                        updated, updatedby, c_projecttask_id, ma_machine_id, 
                        costuom, qty_budget, unit_cost, 
                        total_cost_budget, units_cost_executed, cost_unit_executed, total_cost_executed)
                        VALUES (get_uuid(), v_AD_Client_ID, v_AD_org_ID, 'Y', now(), v_AD_User_ID,
                        now(), v_AD_User_ID, Cur_Task.C_ProjectTask_ID , Cur_Machine.MA_Machine_id , 
                        Cur_Machine.Costuom,  Cur_Machine.Use, Cur_Machine.Cost , 
                        ( Cur_Machine.Cost *  Cur_Machine.Use), 0, 0, 0);
                    END IF;

                END LOOP;


			END LOOP; -- Get Parameter



      v_Message:='';
    END;
    --<<FINISH_PROCESS>>
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message) ;
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', v_Result, v_Message) ;
    RETURN;
  END; --BODY
EXCEPTION
WHEN OTHERS THEN
  v_ResultStr:= '@ERROR=' || SQLERRM;
  DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
  ROLLBACK;
  AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
  RETURN;
END SPROCTM_ASIGNED_CE
